#include <memory>
#include <string_view>

class Connection {
public:
    static auto create(std::string_view host) -> std::unique_ptr<Connection> {
        return std::make_unique<Connection>(host);
    }
    ~Connection() { disconnect(); }
private:
    explicit Connection(std::string_view host) : host_(host) {}
    std::string host_;
};
